# UNOPTIMIZED: Raw SQL with string formatting
def get_item_price(args, item_code, ignore_party=False):
    args["item_code"] = item_code

    # PROBLEM: SQL built with string concatenation
    # - Prone to SQL injection if args not sanitized
    # - Hard to read and maintain
    # - No type checking or autocompletion
    conditions = """where item_code=%(item_code)s
        and price_list=%(price_list)s
        and ifnull(uom, '') in ('', %(uom)s)"""

    conditions += "and ifnull(batch_no, '') in ('', %(batch_no)s)"

    if not ignore_party:
        if args.get("customer"):
            conditions += " and customer=%(customer)s"
        elif args.get("supplier"):
            conditions += " and supplier=%(supplier)s"
        else:
            conditions += (
                "and (customer is null or customer = '') "
                "and (supplier is null or supplier = '')"
            )

    if args.get("transaction_date"):
        conditions += """ and %(transaction_date)s between
            ifnull(valid_from, '2000-01-01') and ifnull(valid_upto, '2500-12-31')"""

    return frappe.db.sql(
        f"""SELECT name, price_list_rate, uom FROM `tabItem Price` {conditions}
        ORDER BY valid_from DESC""",
        args
    )

