# OPTIMIZED: Query Builder with type safety
def get_item_price(pctx: ItemPriceCtx | dict, item_code, ignore_party=False):
    pctx: ItemPriceCtx = frappe._dict(pctx)

    # FIX: Use Query Builder - safer, cleaner, maintainable
    ip = frappe.qb.DocType("Item Price")

    query = (
        frappe.qb.from_(ip)
        .select(ip.name, ip.price_list_rate, ip.uom)
        .where(
            (ip.item_code == item_code)
            & (ip.price_list == pctx.price_list)
            & (ip.uom.isin(["", pctx.uom]) | ip.uom.isnull())
        )
        .orderby(ip.valid_from, order=frappe.qb.desc)
    )

    # Add conditions dynamically in a readable way
    if pctx.batch_no:
        query = query.where(
            (ip.batch_no == pctx.batch_no) | (ip.batch_no.isnull())
        )

    if not ignore_party:
        if pctx.customer:
            query = query.where(ip.customer == pctx.customer)
        elif pctx.supplier:
            query = query.where(ip.supplier == pctx.supplier)

    return query.run(as_dict=True)
